if (!Array.isArray(items)) {
  throw new Error("Invalid input");
}

const allOptions = items.map(item => item.json);

// ✅ 1. Get spot price
const spot = $('NIFTY Spot (LTP)1').first().json.data[0].d[0];

// ✅ 2. Find ATM strike — using correct field name SEM_STRIKE_PRICE
const uniqueStrikes = [...new Set(allOptions.map(opt => opt.SEM_STRIKE_PRICE))];
const nearestStrike = uniqueStrikes.reduce((prev, curr) =>
  Math.abs(curr - spot) < Math.abs(prev - spot) ? curr : prev
);

// ✅ 3. Filter CE/PE for nearestStrike — using correct field names
const atmOptions = allOptions.filter(opt =>
  opt.SEM_STRIKE_PRICE === nearestStrike &&
  (opt.SEM_OPTION_TYPE === 'CE' || opt.SEM_OPTION_TYPE === 'PE')
);

// ✅ 4. Group by expiry and pick earliest — using correct field name SEM_EXPIRY_DATE
const expiryMap = {};
for (const opt of atmOptions) {
  if (!expiryMap[opt.SEM_EXPIRY_DATE]) {
    expiryMap[opt.SEM_EXPIRY_DATE] = [];
  }
  expiryMap[opt.SEM_EXPIRY_DATE].push(opt);
}

// ✅ Fix: Parse "DD-Mon-YYYY" dates correctly for sorting
const monthMap = {
  Jan:0, Feb:1, Mar:2, Apr:3, May:4, Jun:5,
  Jul:6, Aug:7, Sep:8, Oct:9, Nov:10, Dec:11
};

const parseExpiry = (dateStr) => {
  const parts = dateStr.split('-'); // ["25", "Jul", "2025"]
  return new Date(parseInt(parts[2]), monthMap[parts[1]], parseInt(parts[0]));
};

const sortedExpiries = Object.keys(expiryMap).sort((a, b) =>
  parseExpiry(a) - parseExpiry(b)
);

const nearestExpiryOptions = expiryMap[sortedExpiries[0]] || [];

// ✅ 5. Format output — using correct field names
return nearestExpiryOptions.map(opt => ({
  json: {
    strike: opt.SEM_STRIKE_PRICE,
    optionType: opt.SEM_OPTION_TYPE,
    symbol: `NIFTY-${opt.SEM_EXPIRY_DATE}-${opt.SEM_STRIKE_PRICE}-${opt.SEM_OPTION_TYPE}`,
    securityCode: opt.SEM_SMST_SECURITY_ID,
    lotSize: opt.SEM_LOT_UNITS || 75,
    expiry: opt.SEM_EXPIRY_DATE
  }
}));

// ============================================================
// NIFTY Option Chain Builder — Final Version
// Expiry: Tuesday-based (NSE rule since Sep 1, 2025)
// ============================================================

// ✅ 1. Read pre-filtered option data
const rows = $items("Parse master Copy1").map(item => item.json);

// ✅ 2. Spot Price
const spotJson = $node["NIFTY Spot (LTP)1"].json;
const spotPrice = parseFloat(spotJson?.data?.[0]?.d?.[0]);
if (isNaN(spotPrice)) throw new Error("❌ Spot price missing or invalid.");

// ✅ 3. Access Token
const accessToken = "eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzUxMiJ9.eyJpc3MiOiJkaGFuIiwicGFydG5lcklkIjoiIiwiZXhwIjoxNzc0Mzg3MzU0LCJpYXQiOjE3NzQzMDA5NTQsInRva2VuQ29uc3VtZXJUeXBlIjoiU0VMRiIsIndlYmhvb2tVcmwiOiIiLCJkaGFuQ2xpZW50SWQiOiIxMTA3ODQzMTc0In0.HKiV1O5MO6rTu0g2ACizDD3t32Z9YZTLhOrIc51D4V5bJAEHqWyPi7YyQMiu3SMKcF_ns8YM7-L6lMc-bIpnCA";

// ✅ 4. NSE Holidays 2026 that fall on Tuesday (expiry shifts to Monday)
const nseHolidays = new Set([
  "2026-03-03", // Holi           → shifts to 2026-03-02 (Mon)
  "2026-03-31", // Mahavir Jayanti→ shifts to 2026-03-30 (Mon)
  "2026-04-14", // Ambedkar Day   → shifts to 2026-04-13 (Mon)
  "2026-10-20", // Dussehra       → shifts to 2026-10-19 (Mon)
  "2026-11-10", // Diwali         → shifts to 2026-11-09 (Mon)
  "2026-11-24", // Guru Nanak     → shifts to 2026-11-23 (Mon)
]);

// ✅ 5. Compute next active NIFTY expiry (Tuesday-based since Sep 2025)
function getNextNiftyExpiry() {
  const now = new Date();

  // Work in IST (UTC+5:30)
  const IST_OFFSET_MS = 5.5 * 60 * 60 * 1000;
  const ist = new Date(now.getTime() + IST_OFFSET_MS);

  const day = ist.getUTCDay();           // 0=Sun, 1=Mon, 2=Tue ... 6=Sat
  const hours = ist.getUTCHours();       // IST hours in UTC terms
  const minutes = ist.getUTCMinutes();

  // Market closes at 15:30 IST = 10:00 UTC
  const marketClosed = (hours > 10) || (hours === 10 && minutes >= 0);

  // Days until next Tuesday
  let daysToTuesday = (2 - day + 7) % 7;

  // If today IS Tuesday AND market is already closed → this week's expiry is done
  if (daysToTuesday === 0 && marketClosed) {
    daysToTuesday = 7; // jump to next Tuesday
  }

  // Compute the expiry date
  const expiry = new Date(ist);
  expiry.setUTCDate(ist.getUTCDate() + daysToTuesday);

  // Format as YYYY-MM-DD (plain string — avoids n8n #### masking)
  const yyyy = expiry.getUTCFullYear();
  const mm = String(expiry.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(expiry.getUTCDate()).padStart(2, '0');
  let expiryStr = `${yyyy}-${mm}-${dd}`;

  // If it's an NSE holiday → shift back to preceding Monday
  if (nseHolidays.has(expiryStr)) {
    expiry.setUTCDate(expiry.getUTCDate() - 1);
    const dd2 = String(expiry.getUTCDate()).padStart(2, '0');
    expiryStr = `${yyyy}-${mm}-${dd2}`;
  }

  return expiryStr; // Always returns clean "YYYY-MM-DD" string
}

// ✅ 6. Get expiry as clean string (never from rows to avoid format issues)
const expiryDateStr = getNextNiftyExpiry();

// ✅ 7. ATM Strike (NIFTY rounds to nearest 50)
const atmStrike = Math.round(spotPrice / 50) * 50;

// ✅ 8. Sort rows by distance from ATM, pick top 10 CE & PE
rows.forEach(row => {
  row.strike = parseFloat(row.strike);
  row.distanceFromATM = Math.abs(row.strike - atmStrike);
});
rows.sort((a, b) => a.distanceFromATM - b.distanceFromATM);

const ceOptions = rows.filter(row => row.optionType === 'CE').slice(0, 10);
const peOptions = rows.filter(row => row.optionType === 'PE').slice(0, 10);

// ✅ 9. Fetch LTP from Dhan API
async function getLTP(securityId) {
  try {
    const res = await fetch(
      `https://api.dhan.co/v2/marketfeed/ltp?securityId=${securityId}&exchangeSegment=NSE_FNO&instrument=OPTIDX`,
      {
        headers: {
          'access-token': accessToken,
          'Content-Type': 'application/json'
        }
      }
    );
    if (res.ok) {
      const data = await res.json();
      return data?.data?.LTP ?? 0;
    }
  } catch (err) {
    console.error(`❌ LTP fetch failed for ${securityId}:`, err.message);
  }
  return 0;
}

// ✅ 10. Append LTP to each option
const ceWithLTP = [];
const peWithLTP = [];

for (const option of ceOptions) {
  const ltp = await getLTP(option.securityCode);
  ceWithLTP.push({ ...option, ltp });
}

for (const option of peOptions) {
  const ltp = await getLTP(option.securityCode);
  peWithLTP.push({ ...option, ltp });
}

// ✅ 11. Final output
return {
  spotPrice,
  atmStrike,
  expiry: expiryDateStr,          // e.g. "2026-03-02" — always clean string
  ceOptions: ceWithLTP,
  peOptions: peWithLTP,
  totalOptionsFound: rows.length,
  timestamp: new Date().toISOString(),
  token: accessToken
};

// ============================================================
// PREPARE DHAN ORDER — v3.4 (FINAL SYNC: LTP + SECURITY ID)
// ✅ Pulls live LTP AND Security ID from 'Option Chain Request1'
// ============================================================

// 1. Get Signal Data
const signalData = $('🧠 Call Python AI Engine').first().json;
const finalSignal = signalData.finalSignal;

if (["WAIT", "AVOID", "SIDEWAYS"].includes(finalSignal)) {
    return [{ json: { status: "SKIPPED", reason: `Signal is ${finalSignal}`, orderPlaced: false } }];
}

// 2. Get Data Sources
const builder = $('NIFTY Option Chain Builder1').first().json;
const ocData = $('Option Chain Request1').first().json?.data || {};
const ocMap = ocData.oc || {}; 

const atmStrike = builder.atmStrike;
const lotSize = $('Parse master Copy1').first().json.lotSize || 75;

// 3. Determine Side
const isCE = finalSignal === 'BUY CALL (CE)';
const options = isCE ? builder.ceOptions : builder.peOptions;

// 4. Pick Strike
let selectedOption = options.find(opt => opt.strike === atmStrike) || options[0];

// 5. ✅ CRITICAL: Sync both LTP and Security ID from Option Chain Request1
const strikeVal = parseFloat(selectedOption.strike);
const strikeKey = strikeVal.toFixed(2);
// Try multiple formats to ensure we find the key (e.g., "25200.00", "25200", "25200.000000")
const liveData = ocMap[strikeKey] || ocMap[strikeVal.toString()] || ocMap[`${strikeVal}.000000`];

if (liveData) {
    const liveSide = isCE ? liveData.ce : liveData.pe;
    if (liveSide) {
        selectedOption.ltp = liveSide.last_price || 0;
        // ✅ OVERRIDE THE MISMATCHING ID WITH THE LIVE ONE (e.g., 54904)
        selectedOption.securityCode = liveSide.security_id.toString();
    }
}

// 6. Build Order
const dhanOrder = {
    dhanClientId: "1107843174",
    correlationId: `SIG_${Date.now()}`,
    transactionType: "BUY",
    exchangeSegment: "NSE_FNO",
    productType: "INTRADAY",
    orderType: "MARKET",
    validity: "DAY",
    securityId: selectedOption.securityCode, // Now correctly uses the live ID
    quantity: lotSize
};

return [{
    json: {
        dhanOrder,
        selectedOption,
        finalSignal,
        ltp: selectedOption.ltp,
        tradingSymbol: selectedOption.symbol,
        orderPlaced: true,
        timestamp: new Date().toISOString()
    }
}];

// Enhanced Exit Order Monitor for Dhan API
const orderBook = $node['Get Dhan Order Book'].json.data || [];
const activeTrades = $node['Get Active Dhan Trades'].json || [];
const accessToken = $node['Dhan Authentication1'].json.data.access_token;

const results = [];
const ordersToCancel = [];
const tradesToUpdate = [];
const notifications = [];

// Process each active trade
activeTrades.forEach(tradeRow => {
  if (tradeRow.Status !== 'ACTIVE') return;

  const entryOrderId = tradeRow['Entry Order ID'];
  const slOrderId = tradeRow['SL Order ID'];
  const targetOrderId = tradeRow['Target Order ID'];
  const tradingSymbol = tradeRow['Trading Symbol'];
  const entryPrice = parseFloat(tradeRow['Entry Price']);
  const quantity = parseInt(tradeRow['Quantity']);

  // Find these orders in the current order book
  const slOrder = orderBook.find(order => order.orderId === slOrderId);
  const targetOrder = orderBook.find(order => order.orderId === targetOrderId);

  let executedOrder = null;
  let orderToCancel = null;
  let exitType = null;
  let exitPrice = null;
  let pnl = 0;

  // Check if SL order is executed
  if (slOrder && slOrder.orderStatus === 'TRADED') {
    executedOrder = slOrder;
    orderToCancel = targetOrderId;
    exitType = 'STOP_LOSS';
    exitPrice = parseFloat(slOrder.price);
    pnl = (exitPrice - entryPrice) * quantity;

    notifications.push({
      type: 'STOP_LOSS_HIT',
      message: `Stop Loss executed for ${tradingSymbol} at ₹${exitPrice}`,
      pnl: pnl,
      severity: pnl < 0 ? 'HIGH' : 'MEDIUM'
    });
  }
  // Check if Target order is executed
  else if (targetOrder && targetOrder.orderStatus === 'TRADED') {
    executedOrder = targetOrder;
    orderToCancel = slOrderId;
    exitType = 'TARGET';
    exitPrice = parseFloat(targetOrder.price);
    pnl = (exitPrice - entryPrice) * quantity;

    notifications.push({
      type: 'TARGET_ACHIEVED',
      message: `Target achieved for ${tradingSymbol} at ₹${exitPrice}`,
      pnl: pnl,
      severity: 'LOW'
    });
  }
  // Check for partial executions or pending status changes
  else {
    // Monitor for any status changes that might need attention
    if (slOrder && slOrder.orderStatus === 'REJECTED') {
      notifications.push({
        type: 'SL_ORDER_REJECTED',
        message: `SL order rejected for ${tradingSymbol}`,
        severity: 'HIGH'
      });
    }

    if (targetOrder && targetOrder.orderStatus === 'REJECTED') {
      notifications.push({
        type: 'TARGET_ORDER_REJECTED',
        message: `Target order rejected for ${tradingSymbol}`,
        severity: 'HIGH'
      });
    }
  }

  if (executedOrder && orderToCancel) {
    // Add order to cancel list
    ordersToCancel.push({
      orderId: orderToCancel,
      tradingSymbol: tradingSymbol
    });

    // Calculate additional metrics
    const riskAmount = Math.abs(entryPrice - parseFloat(tradeRow['Stop Loss']));
    const rewardAmount = Math.abs(parseFloat(tradeRow['Target']) - entryPrice);
    const actualRR = exitType === 'TARGET' ? 
      Math.abs(pnl) / (riskAmount * quantity) : 
      -Math.abs(pnl) / (riskAmount * quantity);

    // Update trade information
    tradesToUpdate.push({
      entryOrderId: entryOrderId,
      exitType: exitType,
      exitPrice: exitPrice,
      pnl: Math.round(pnl * 100) / 100,
      executedOrderId: executedOrder.orderId,
      actualRiskReward: Math.round(actualRR * 100) / 100,
      executionTime: executedOrder.updateTime || new Date().toISOString(),
      timestamp: new Date().toISOString()
    });

    results.push({
      message: `${exitType} executed for ${tradingSymbol}`,
      entryOrderId: entryOrderId,
      tradingSymbol: tradingSymbol,
      exitPrice: exitPrice,
      pnl: pnl,
      cancelOrderId: orderToCancel,
      exitType: exitType
    });
  }
});

// Calculate session statistics
const sessionStats = {
  totalExecutions: results.length,
  totalPnL: tradesToUpdate.reduce((sum, trade) => sum + trade.pnl, 0),
  targetHits: tradesToUpdate.filter(t => t.exitType === 'TARGET').length,
  stopLossHits: tradesToUpdate.filter(t => t.exitType === 'STOP_LOSS').length,
  avgPnL: tradesToUpdate.length > 0 ? 
    tradesToUpdate.reduce((sum, trade) => sum + trade.pnl, 0) / tradesToUpdate.length : 0
};

return {
  results,
  ordersToCancel,
  tradesToUpdate,
  notifications,
  sessionStats,
  totalExecutions: results.length,
  timestamp: new Date().toISOString()
};

const trades = $node['Analyze Dhan Exit Executions'].json.tradesToUpdate || [];
const ordersToCancel = $node['Analyze Dhan Exit Executions'].json.ordersToCancel || [];

// Return each trade combined with its corresponding cancellation ID
return trades.map(trade => {
  const cancelOrder = ordersToCancel.find(o => o.tradingSymbol === trade.tradingSymbol);
  return {
    ...trade,
    cancelOrderId: cancelOrder ? cancelOrder.orderId : null
  };
}).filter(t => t.cancelOrderId !== null);

const orderStatus = $node['Get Order Status'].json.data;
const orderData = $node['Prepare Dhan Order1']?.json || {};

if (orderStatus.orderStatus !== 'TRADED') {
    throw new Error(`Order not executed. Status: ${orderStatus.orderStatus}`);
}

// Use averageTradedPrice for execution price
const fillPrice = parseFloat(orderStatus.averageTradedPrice || orderStatus.price);
const quantity = parseInt(orderStatus.quantity);
const securityId = orderStatus.securityId;
const tradingSymbol = orderData.selectedOption?.tradingSymbol || orderData.selectedOption?.symbol || '';

// Round to 0.05 tick size (required by exchange)
const roundToTick = (p) => Math.round(p * 20) / 20;

// ==========================================
// 🎯 SETUP RISK / REWARD IN POINTS (RUPEES)
// ==========================================
const SL_POINTS = 10;     // 10 Rs Stop Loss
const TARGET_POINTS = 20; // 20 Rs Take Profit

// Calculate Absolute Prices
const stopLossPrice = roundToTick(Math.max(fillPrice - SL_POINTS, 0.05)); // Ensures price doesn't go below 0.05
const targetPrice = roundToTick(fillPrice + TARGET_POINTS);

return {
    entryOrderId: orderStatus.orderId,
    fillPrice, 
    quantity, 
    securityId, 
    tradingSymbol,
    stopLoss: stopLossPrice,
    target: targetPrice,
    riskAmount: Math.round((fillPrice - stopLossPrice) * 100) / 100,
    rewardAmount: Math.round((targetPrice - fillPrice) * 100) / 100,
    executionTime: orderStatus.createTime,
    timestamp: new Date().toISOString()
};
